{
    "code": "ct_pds_temp",
    "description" : "Table des fichiers json découpés des pds",
    "disabled": false,
    "name": "ct_pds_temp",
    "storeInES": false,
    "storeAsTable": true,
    "field": [
        {
            "code": "id_pds_interface",
            "description": "ID du PDS de la table ct_pds_interface ",
            "fieldType": "LONG"
        },
        {
            "code": "id_pds",
            "description": "Identifiant du PDS",
            "fieldType": "STRING"
        },
        {
            "code": "date_pds",
            "description": "Date à laquelle la pds a été effectuée",
            "fieldType": "STRING"
        },
        {
            "code": "nom_fichier",
            "description": "Nom du fichier json",
            "fieldType": "STRING"
        },
        {
            "code": "date_last_update",
            "description": "Date de dernière modification dans Next Energie",
            "fieldType": "STRING"
        },
        {
            "code": "contenu",
            "description": "Contenu json du pds",
            "fieldType": "TEXT_AREA"
        },
        {
            "code": "statut",
            "description": "Statut",
            "fieldType": "LIST",
            "listValues": {
                "TRAITE": "TRAITE",
                "A_TRAITER": "A_TRAITER",
                "ERREUR": "ERREUR"
            }
        },
        {
            "code": "date_traitement",
            "description": "Date identique l'entrée de ct_pds_interface",
            "fieldType": "STRING"
        },
        {
            "code": "code_erreur",
            "description": "Code erreur",
            "fieldType": "STRING"
        },
        {
            "code": "message_erreur",
            "description": "Message erreur",
            "fieldType": "STRING",
            "maxValue":4000
        }
    ],
    "action": []
}
